import * as React from "react";
import styled from "styled-components";
import { Spinner } from "./form-sections";
import { media } from "./media-queries";
import { BaseSubmitButton } from "../components/ButtonLink";

/*
        action="https://europe-west1-vosbor-io.cloudfunctions.net/function-vosbor-form-mailer"
        method="POST"
        autoComplete="off"
        enctype="multipart/form-data"
*/

export const ContactForm = ({ type }) => {
  const [name, setName] = React.useState(null);
  const [company, setCompany] = React.useState(null);
  const [email, setEmail] = React.useState(null);
  const [message, setMessage] = React.useState(null);

  const [loading, setLoading] = React.useState(false);

  const onFormSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    const url =
      "https://europe-west1-vosbor-io.cloudfunctions.net/function-vosbor-form-mailer";
    const formData = new FormData();
    formData.append("type", type);
    formData.append("name", name);
    formData.append("company", company);
    formData.append("email", email);
    formData.append("message", message);
    const config = {
      method: "POST",
      mode: "cors",
      cache: "no-cache",
      body: formData,
    };

    try {
      const response = await fetch(url, config);

      console.log(response.data);
      window.location = "/response-ok";
    } catch (error) {
      console.log("ERROR:", error);
      setLoading(false);
    }
  };

  return (
    <FormWrapper>
      {loading && <Spinner />}
      <Form onSubmit={onFormSubmit}>
        <input type="hidden" name="type" value={type} />
        <InputText
          type="text"
          placeholder="Full Name"
          name="name"
          autoComplete="off"
          onChange={(e) => setName(e?.target?.value)}
          disabled={loading ? "disabled" : ""}
        />
        <InputText
          type="text"
          placeholder="Company"
          name="company"
          autoComplete="off"
          onChange={(e) => setCompany(e?.target?.value)}
          disabled={loading ? "disabled" : ""}
        />
        <InputText
          type="email"
          placeholder="Email address"
          name="email"
          autoComplete="off"
          onChange={(e) => setEmail(e?.target?.value)}
          disabled={loading ? "disabled" : ""}
          required
        />
        <Textarea
          placeholder="Message"
          name="message"
          autoComplete="off"
          onChange={(e) => setMessage(e?.target?.value)}
          disabled={loading ? "disabled" : ""}
          required
        ></Textarea>
        <InfoText>
          Your data will only be used by authorised Vosbor personnel, not
          distributed to third parties and only used to contact you and to send
          you our newsletter. By using the contact form you agree to our privacy
          policy.
        </InfoText>
        <SubmitButton disabled={loading ? "disabled" : ""}>Submit</SubmitButton>
      </Form>
    </FormWrapper>
  );
};

const FormWrapper = styled.div`
  ${media.m`
    display: flex;
    flex-direction: column;
    align-items: center;
  `}
`;

const Form = styled.form`
  display: flex;
  flex-direction: column;
  align-items: stretch;
  gap: 15px;

  ${media.m`
    max-width: 560px;
    width: 100%;
  `}
`;

const InputText = styled.input`
  padding: 15px 24px;
  color: #47474f;
  font-family: "Roboto";
  font-size: 18px;
  border: 2px solid rgba(116, 116, 135, 0.33);
  height: 50px;
  box-sizing: border-box;

  &:active,
  &:focus {
    color: #060831;
    outline: none;
    border: 2px solid #4200ff;
  }

  &:disabled {
    background: #0000001a;
    opacity: 0.5;
  }
`;

const Textarea = styled.textarea`
  padding: 15px 24px;
  color: #47474f;
  font-family: "Roboto";
  font-size: 18px;
  border: 2px solid rgba(116, 116, 135, 0.33);
  min-height: 168px;
  resize: none;
  box-sizing: border-box;

  &:active,
  &:focus {
    color: #060831;
    outline: none;
    border: 2px solid #4200ff;
  }

  &:disabled {
    background: #0000001a;
    opacity: 0.5;
  }
`;

const SubmitButton = styled(BaseSubmitButton)`
  color: #ffffff;
  background: #4200ff;

  ${media.m`
    align-self: end;
  `}

  &:disabled {
    opacity: 0.5;
  }
`;

const InfoText = styled.span`
  font-family: Roboto;
  font-style: normal;
  font-weight: normal;
  font-size: 9px;
  line-height: 17px;
  text-align: right;
  letter-spacing: 0.002em;

  color: #060831;
`;
